"""
routes.py — API 路由模块

定义所有 RESTful API 端点，按模块组织路由。
"""

from fastapi import APIRouter, HTTPException
from typing import Optional

from models import (
    ApiResponse,
    ApplyReservationRequest,
    PayInAdvanceRequest,
    UpdateParkConfigRequest,
)
from services import (
    # 园区配置
    get_all_parks,
    update_park_config,
    get_admin_status,
    # 预约申请
    check_available,
    apply_reservation,
    # 预约取消
    cancel_reservation,
    # 提前缴费
    pay_in_advance,
    # 数据查询
    get_remaining_spots,
    query_my_reservations,
    get_all_reservations,
    get_park_detail,
    # 科拓对接
    push_to_ketuo,
    update_ketuo_status,
    insert_payment_record,
)
from utils import logger

router = APIRouter(prefix="/api/v1")


# ============================================================
# 系统配置类接口
# ============================================================

@router.get("/parks", response_model=ApiResponse)
async def api_get_parks():
    """获取所有园区配置。"""
    try:
        data = get_all_parks()
        return ApiResponse(code=200, message="success", data=data)
    except Exception as e:
        logger.error(f"获取园区配置失败: {e}")
        return ApiResponse(code=500, message=f"服务器内部错误", data=None)


@router.get("/parks/{park_id}", response_model=ApiResponse)
async def api_get_park(park_id: int):
    """获取单个园区详情。"""
    try:
        data = get_park_detail(park_id)
        if data is None:
            return ApiResponse(code=404, message="园区不存在", data=None)
        return ApiResponse(code=200, message="success", data=data)
    except Exception as e:
        logger.error(f"获取园区详情失败: {e}")
        return ApiResponse(code=500, message="服务器内部错误", data=None)


@router.put("/parks/{park_id}", response_model=ApiResponse)
async def api_update_park_config(park_id: int, req: UpdateParkConfigRequest):
    """更新园区配置。"""
    try:
        success, msg = update_park_config(
            park_id=park_id,
            workday_quota=req.workday_quota,
            holiday_quota=req.holiday_quota,
            is_open=req.is_open,
            description=req.description,
        )
        if not success:
            return ApiResponse(code=400, message=msg, data=None)
        return ApiResponse(code=200, message=msg, data=None)
    except Exception as e:
        logger.error(f"更新园区配置失败: {e}")
        return ApiResponse(code=500, message="服务器内部错误", data=None)


@router.get("/admin/status", response_model=ApiResponse)
async def api_admin_status():
    """管理员获取概览状态。"""
    try:
        data = get_admin_status()
        return ApiResponse(code=200, message="success", data=data)
    except Exception as e:
        logger.error(f"获取管理员概览失败: {e}")
        return ApiResponse(code=500, message="服务器内部错误", data=None)


